const container = document.getElementById("posts");

function render(list){
container.innerHTML="";
list.forEach(p=>{
const card=document.createElement("div");
card.className="card";
card.innerHTML=`<img src="${p.hero}"><h3>${p.city}</h3>`;
card.onclick=()=>openPost(p);
container.appendChild(card);
});
}

render(posts);

document.getElementById("search").addEventListener("input",e=>{
const q=e.target.value.toLowerCase();
render(posts.filter(p=>p.city.toLowerCase().includes(q)));
});

function openPost(p){
document.getElementById("viewer").classList.remove("hidden");
document.getElementById("title").innerText=p.city+" — "+p.country;
document.getElementById("heroImg").src=p.hero;
document.getElementById("foodImg").src=p.food;
document.getElementById("content").innerText=p.text;
window.scrollTo(0,0);
}

function closePost(){
document.getElementById("viewer").classList.add("hidden");
}
